1	------------------------------------------------------------------------------
2	--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This is a very basic clock crossing that allows passing of static-data
11	-- (i.e. data that is not sample based) from one clock domain to another. This
12	-- entity ensures that the data is passed correctly at some point of time but
13	-- it does not specify an exact sample point.
14	-- The main use cause of this entity is to pass status information or configuration
15	-- register values between clock domains.
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.numeric_std.all;
20	
21	-- @formatter:off
22	entity psi_common_status_cc is
23	  generic(width_g      : positive := 16;                                -- data width in bits
24	          a_rst_pol_g  : std_logic:= '1';                               -- reset pol port a, '1' active high
25	          b_rst_pol_g  : std_logic:= '1');                              -- reset pol port b, '1' active high
26	  port(   a_clk_i      : in  std_logic;                                 -- Clock A
27	          a_rst_i      : in  std_logic;                                 -- Clock domain A sync reset
28	          a_rst_o      : out std_logic;                                 -- Clock domain A reset output, active if a_rst_i or b_rst_i is asserted, de-asserted synchronously to clk A
29	          a_dat_i      : in  std_logic_vector(width_g - 1 downto 0);    -- Clock domain A data input
30	          b_clk_i      : in  std_logic;                                 -- Clock B
31	          b_rst_i      : in  std_logic;                                 -- Clock domain B sync reset
32	          b_rst_o      : out std_logic;                                 -- Clock domain A reset output, active if a_rst_i or b_rst_i is asserted, de-asserted synchronously to clk A
33	          b_dat_o      : out std_logic_vector(width_g - 1 downto 0));   -- Clock domain B data output
34	end entity;
35	-- @formatter:on
36	
37	architecture rtl of psi_common_status_cc is
38	  signal RstIntA       : std_logic;
39	  signal RstIntB       : std_logic;
40	  signal Started       : std_logic;
41	  signal RstIntBSync   : std_logic_vector(1 downto 0);
42	  signal VldA          : std_logic;
43	  signal RecToggle     : std_logic;
44	  signal VldB          : std_logic;
45	  signal RecToggleSync : std_logic_vector(2 downto 0);
46	
47	  attribute syn_srlstyle : string;
48	  attribute syn_srlstyle of RstIntBSync   : signal is "registers";
49	  attribute syn_srlstyle of RecToggle     : signal is "registers";
50	  attribute syn_srlstyle of RecToggleSync : signal is "registers";
51	  attribute shreg_extract : string;
52	  attribute shreg_extract of RstIntBSync    : signal is "no";
53	  attribute shreg_extract of RecToggle      : signal is "no";
54	  attribute shreg_extract of RecToggleSync  : signal is "no";
55	  attribute ASYNC_REG : string;
56	  attribute ASYNC_REG of RstIntBSync : signal is "TRUE";
57	  attribute ASYNC_REG of RecToggle : signal is "TRUE";
58	  attribute ASYNC_REG of RecToggleSync : signal is "TRUE";
59	
60	begin
61	
62	  -- Valid pulse generation
63	  p_vldgen : process(a_clk_i)
64	  begin
65	    if rising_edge(a_clk_i) then
66	      if RstIntA = a_rst_pol_g then
67	        RstIntBSync   <= (others => '1');
68	        Started       <= '0';
69	        VldA          <= '0';
70	        RecToggleSync <= (others => '0');
71	      else
72	        -- default values
73	        VldA          <= '0';
74	        -- Synchronize signals of clock domain B
75	        RstIntBSync   <= RstIntBSync(RstIntBSync'left - 1 downto 0) & RstIntB;
76	        RecToggleSync <= RecToggleSync(RecToggleSync'left - 1 downto 0) & RecToggle;
77	        -- Generation of first vld pulse
78	        if (Started = '0') and (RstIntBSync(RstIntBSync'left) = '0') then
79	          VldA    <= '1';
80	          Started <= '1';
81	        end if;
82	        -- Send next value because other clockdomain received last data
83	        if RecToggleSync(RecToggleSync'left) /= RecToggleSync(RecToggleSync'left - 1) then
84	          VldA <= '1';
85	        end if;
86	      end if;
87	    end if;
88	  end process;
89	
90	  -- Reception detection
91	  p_recdet : process(b_clk_i)
92	  begin
93	    if rising_edge(b_clk_i) then
94	      if RstIntB = b_rst_pol_g then
95	        RecToggle <= '0';
96	      else
97	        if VldB = '1' then
98	          RecToggle <= not RecToggle;
99	        end if;
100	      end if;
101	    end if;
102	  end process;
103	
104	  -- instantiation of simple CC
105	  i_scc : entity work.psi_common_simple_cc
106	    generic map(
107	      width_g => width_g,
108	      a_rst_pol_g  => a_rst_pol_g,
109	      b_rst_pol_g  => b_rst_pol_g
110	    )
111	    port map(
112	      a_clk_i => a_clk_i,
113	      a_rst_i => a_rst_i,
114	      a_rst_o => RstIntA,
115	      a_dat_i => a_dat_i,
116	      a_vld_i => VldA,
117	      b_clk_i => b_clk_i,
118	      b_rst_i => b_rst_i,
119	      b_rst_o => RstIntB,
120	      b_dat_o => b_dat_o,
121	      b_vld_o => VldB
122	    );
